/// Standalone function: sum a vector of file sizes and check against available disk space.
/// Returns Ok(total) if the files fit, or an appropriate error otherwise.
pub fn calculate_batch_download_size(
    file_sizes: &[u64],
    available_disk_space: u64,
) -> Result<u64, BatchDownloadError> {
    if file_sizes.is_empty() {
        return Err(BatchDownloadError::EmptyFileList);
    }

    let mut total: u64 = 0;
    for &size in file_sizes {
        total = total.checked_add(size).ok_or(BatchDownloadError::Overflow)?;
    }

    if total > available_disk_space {
        Err(BatchDownloadError::InsufficientDiskSpace {
            required: total,
            available: available_disk_space,
        })
    } else {
        Ok(total)
    }
}

/// Fast version using wrapping_add — no overflow detection.
pub fn calculate_batch_download_size_fast(file_sizes: &[u64]) -> Result<u64, BatchDownloadError> {
    if file_sizes.is_empty() {
        return Err(BatchDownloadError::EmptyFileList);
    }

    let total = file_sizes
        .iter()
        .fold(0u64, |acc, &size| acc.wrapping_add(size));

    Ok(total)
}

